#!/usr/bin/env python3
"""
Bug #2213: jax.jit (XLA) produces wrong output vs PyTorch eager reference.

Patterns    : [['layout', 'transpose_matmul_transpose'], ['constant', 'cast_roundtrip'], ['layout', 'row_reduce_mul_transpose'], ['attention', 'multi_query_attention'], ['layout', 'squeeze_unsqueeze'], ['constant', 'pow_canonical']]
Dependencies: numpy jax
Run         : python unique_2213.py  →  exit 0 = BUG REPRODUCED
"""
import sys
import numpy as np
import jax, jax.numpy as jnp
from jax import lax
import jax.scipy.special

# ── Model weights ─────────────────────────────────────────────────────────────
_w0 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])
_w1 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])
_w2 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 32])
_w3 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 32])
_w4 = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([128, 128])
_w5 = np.frombuffer(bytes.fromhex("f304353e"), dtype=np.float32).reshape([1])
_w6 = np.frombuffer(bytes.fromhex("0100000000000000200000000000000004000000000000002000000000000000"), dtype=np.int64).reshape([4])
_w7 = np.frombuffer(bytes.fromhex("0100000000000000010000000000000020000000000000002000000000000000"), dtype=np.int64).reshape([4])
_w8 = np.frombuffer(bytes.fromhex("0100000000000000040000000000000020000000000000002000000000000000"), dtype=np.int64).reshape([4])
_w9 = np.frombuffer(bytes.fromhex("010000000000000020000000000000008000000000000000"), dtype=np.int64).reshape([3])
_w10 = np.frombuffer(bytes.fromhex("0300000000000000"), dtype=np.int64).reshape([1])
_w11 = np.frombuffer(bytes.fromhex("0300000000000000"), dtype=np.int64).reshape([1])
_w12 = np.frombuffer(bytes.fromhex("00000040"), dtype=np.float32).reshape([1])
_w13 = np.frombuffer(bytes.fromhex("bd378635"), dtype=np.float32).reshape([1])

# ── Triggering input ─────────────────────────────────────────────────────────
INPUT = np.frombuffer(bytes.fromhex(""), dtype=np.float32).reshape([1, 32, 128])  # input "model_input"

EXPECTED = np.frombuffer(bytes.fromhex(""), dtype=np.float32)  # pytorch_eager reference


# ── Model computation (translated from ONNX) ──────────────────────────────────
def model(x):
    n0_tmmt_tr1 = jnp.transpose(x, [0, 2, 1])
    n0_tmmt_tr2 = jnp.transpose(n0_tmmt_tr1, [0, 2, 1])
    n0_tmmt_mm = jnp.matmul(n0_tmmt_tr2, _w0)
    n0_tmmt_out = jnp.transpose(n0_tmmt_mm, [0, 2, 1])
    n0_tmmt_final = jnp.transpose(n0_tmmt_out, [0, 2, 1])
    n100_crt_f16 = n0_tmmt_final.astype(np.float32)
    n100_crt_out = n100_crt_f16.astype(np.float32)
    n200_rrmt_mean = jnp.mean(n100_crt_out, axis=(-1,), keepdims=True)
    n200_rrmt_sub = n100_crt_out - n200_rrmt_mean
    n200_rrmt_scl = n200_rrmt_sub * n200_rrmt_sub
    n200_rrmt_tp = jnp.transpose(n200_rrmt_scl, [0, 2, 1])
    n200_rrmt_out = jnp.transpose(n200_rrmt_tp, [0, 2, 1])
    n300_mqa_q = jnp.matmul(n200_rrmt_out, _w1)
    n300_mqa_k = jnp.matmul(n200_rrmt_out, _w2)
    n300_mqa_v = jnp.matmul(n200_rrmt_out, _w3)
    n300_mqa_qs = jnp.reshape(n300_mqa_q, [int(v) for v in _w6.flat])
    n300_mqa_qt = jnp.transpose(n300_mqa_qs, [0, 2, 1, 3])
    n300_mqa_kus = jnp.reshape(n300_mqa_k, [int(v) for v in _w7.flat])
    n300_mqa_ke = jnp.broadcast_to(n300_mqa_kus, _w8.tolist())
    n300_mqa_vus = jnp.reshape(n300_mqa_v, [int(v) for v in _w7.flat])
    n300_mqa_ve = jnp.broadcast_to(n300_mqa_vus, _w8.tolist())
    n300_mqa_ktt = jnp.transpose(n300_mqa_ke, [0, 1, 3, 2])
    n300_mqa_raw = jnp.matmul(n300_mqa_qt, n300_mqa_ktt)
    n300_mqa_sc = n300_mqa_raw * _w5
    n300_mqa_sm = (lambda _x: _x / jnp.sum(_x, axis=3, keepdims=True))(jnp.exp(n300_mqa_sc - jnp.max(n300_mqa_sc, axis=3, keepdims=True)))
    n300_mqa_ctx = jnp.matmul(n300_mqa_sm, n300_mqa_ve)
    n300_mqa_ct = jnp.transpose(n300_mqa_ctx, [0, 2, 1, 3])
    n300_mqa_cm = jnp.reshape(n300_mqa_ct, [int(v) for v in _w9.flat])
    n300_mqa_out = jnp.matmul(n300_mqa_cm, _w4)
    n400_su_sq = (lambda _x, _ax: jnp.expand_dims(_x, axis=int(_ax.flat[0])))(n300_mqa_out, _w10)
    n400_su_out = jnp.squeeze(n400_su_sq)
    n500_pwc_abs = jnp.abs(n400_su_out)
    n500_pwc_add = n500_pwc_abs + _w13
    n500_pwc_sq = n500_pwc_add ** np.float32(_w12.flat[0])
    n500_pwc_out = jnp.sqrt(n500_pwc_sq)
    return jnp.asarray(n500_pwc_out, dtype=jnp.float32)


if __name__ == "__main__":
    x_jax = jnp.array(INPUT)
    out = np.array(jax.jit(model)(x_jax), dtype=np.float32).ravel()

    diff = float(np.linalg.norm(EXPECTED.astype(np.float64) - out.astype(np.float64))
                 / (np.linalg.norm(EXPECTED.astype(np.float64)) + 1e-8))
    print(f"expected (pytorch_eager): {EXPECTED[:6]}")
    print(f"actual   (jax.jit/XLA) : {out[:6]}")
    print(f"rel L2 : {diff:.4e}")
    if diff > 0.001:
        print("BUG REPRODUCED")
        sys.exit(0)
    sys.exit(1)
